func ListOrders(db *sql.DB, sortCol string) (*sql.Rows, error) {
    // identifiers can't be bound — validate against an allowlist
    allowed := map[string]bool{"id": true, "total": true, "created_at": true}
    if !allowed[sortCol] {
        sortCol = "id"
    }
    q := "SELECT id, total FROM orders ORDER BY " + sortCol
    return db.Query(q)
}
